import math

def process_payment(user, cart_items, payment_details):
    # Define discount percentages based on roles
    DISCOUNT_RATES = {
        "basic": 0.0,
        "premium": 0.15,
        "enterprise": 0.30
    }

    # Validate user role and get discount rate
    user_role = user.get("role", "basic") # Default to basic if role is missing
    discount_rate = DISCOUNT_RATES.get(user_role, 0.0) # Default to no discount for unknown roles

    # Calculate cart total
    cart_total = sum(item.get("price", 0) * item.get("quantity", 1) for item in cart_items)

    # Apply discount
    discount_amount = cart_total * discount_rate
    final_amount = cart_total - discount_amount

    # Ensure final amount is not negative due to floating point inaccuracies, though unlikely with discounts
    final_amount = max(0, final_amount)

    # Process payment (this is a placeholder for actual payment gateway interaction)
    payment_successful = False
    payment_reference = None

    try:
        # Simulate payment gateway interaction
        # In a real application, you would integrate with a payment gateway (e.g., Stripe, PayPal)
        # This would involve API calls, error handling, etc.
        if final_amount > 0:
            # Assume successful payment for non-zero amounts
            payment_successful = True
            payment_reference = f"PAYREF_{hash(f'{user.get("id", "guest")}-{final_amount}-{payment_details.get("card_number", "")[-4:]}')}"
        elif final_amount == 0 and cart_total > 0:
            # Handle cases where discount makes total zero (e.g., 100% discount, though not in this spec)
            payment_successful = True
            payment_reference = f"PAYREF_FREE_{hash(f'{user.get("id", "guest")}-{cart_total}')}"
        else:
            # Cart total was 0, no payment needed
            payment_successful = True
            payment_reference = "NO_PAYMENT_NEEDED_EMPTY_CART"

    except Exception as e:
        # Log the error and handle payment failure
        print(f"Payment processing failed: {e}")
        payment_successful = False
        payment_reference = None

    return {
        "user_id": user.get("id"),
        "cart_total_before_discount": round(cart_total, 2),
        "discount_applied_percentage": round(discount_rate * 100, 2),
        "discount_amount": round(discount_amount, 2),
        "final_amount_to_pay": round(final_amount, 2),
        "payment_successful": payment_successful,
        "payment_reference": payment_reference,
        "payment_details_used": payment_details # Potentially mask sensitive info
    }